definition.script:
@Library("Shared") _
pipeline {
    agent { label "aru" }

    environment {
        IMAGE_NAME = "notes-app"
        IMAGE_TAG  = "latest"
    }

    stages {

        stage("Clean Workspace") {
            steps {
                deleteDir()
            }
        }

        stage("Hello") {
            steps {
                script {
                    hello()
                }
            }
        }

        stage("Clone") {
            steps {
                script {
                    clone("https://github.com/ARPITPRAJAPATI/django-notes-app.git", "dev")
                }
            }
        }

        stage("Build Docker Image") {
            steps {
                script {
                    docker_build("${IMAGE_NAME}", "${IMAGE_TAG}", "aruhehe")
                }
            }
        }

        stage("Push to DockerHub") {
            steps {
               script{
                   docker_push("notes-app", "latest", "aruhehe")
               }
            }
        }

        stage("Deploy") {
            steps {
                echo "Deploying container"
                sh "docker compose down || true"
                sh "docker compose up -d"
            }
        }

        stage("Cleanup") {
            steps {
                echo "Cleaning unused Docker resources"
                sh "docker system prune -f"
            }
        }
    }
}
